    ];

    // Apply pagination
    const paginatedUsers = users.slice(offset, offset + limit);

    res.json({
      data: paginatedUsers,
      total: users.length,
      limit,
      offset
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    next(error); // Pass to error handler
  }
});

